mapper.select:
select ft.id, ft.created_time, ft.created_timestamp, ft.created_by, ft.modified_time, ft.modified_timestamp, ft.modified_by, ft.version, ft.code, ft.name, ft.type, ft.instance_id, fi.name as instance_name, fi.biz_number, fi.current_node_name, ft.model_id, fm.name as model_name, fm.code as model_code from flow_task ft inner join flow_task_player ftp on ft.id = ftp.task_id and ftp.deleted = 0 inner join flow_instance fi on ft.instance_id = fi.id and fi.deleted = 0 inner join flow_model fm on ft.model_id = fm.id and fm.deleted = 0 where ft.deleted = 0 and ( (ftp.type = 0 and ftp.player_id = #{ew.userId})
or (ftp.type = 1 and ftp.player_id in
#{roleId}
)
)
and ft.name like concat('%', #{ew.taskName}, '%')
and fi.name like concat('%', #{ew.instanceName}, '%')
and fi.biz_number = #{ew.bizNumber}
order by ft.modified_time desc
